import{c as a,Q as s,j as n,m as o}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"CAP 与一致性谱","description":"","frontmatter":{},"headers":[],"relativePath":"systemDesign/04-CAP与一致性谱.md","filePath":"systemDesign/04-CAP与一致性谱.md","lastUpdated":1778496697000}'),e={name:"systemDesign/04-CAP与一致性谱.md"};function r(l,t,i,d,p,c){return s(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="cap-与一致性谱" tabindex="-1">CAP 与一致性谱 <a class="header-anchor" href="#cap-与一致性谱" aria-label="Permalink to &quot;CAP 与一致性谱&quot;">​</a></h1><p>CAP 是被讲得最烂、被理解得最差的分布式定理。<strong>99% 的人都背得出 &quot;Consistency / Availability / Partition tolerance 三选二&quot;,但 99% 的人都答错了&quot;二选什么&quot;</strong>——你不能&quot;选 CA 放弃 P&quot;,因为 P 是网络分区,<strong>它不由你选,由物理决定</strong>。这一篇把 CAP 的工程含义讲清楚,然后告诉你<strong>真实工程不在 0/1 二选,而在一个连续光谱上</strong>——从强一致到最终一致中间有 5-6 档,选错一档系统就崩。</p><blockquote><p>一句话先记住:<strong>CAP 真正的含义是&quot;网络分区发生时(P 不可避免),你必须在一致性 C 和可用性 A 之间二选一&quot;</strong>——不是平时三选二,是分区时二选一。<strong>BASE 是 CAP 的实战版本</strong>——「基本可用 + 软状态 + 最终一致」,这套思路撑起了几乎所有互联网公司。<strong>一致性是个光谱</strong>,不是开关——选错档位,要么超时炸要么数据脏。</p></blockquote><hr><h2 id="一、cap-的真正含义-教科书没讲清的" tabindex="-1">一、CAP 的真正含义(教科书没讲清的) <a class="header-anchor" href="#一、cap-的真正含义-教科书没讲清的" aria-label="Permalink to &quot;一、CAP 的真正含义(教科书没讲清的)&quot;">​</a></h2><p>CAP 三个字母:</p><ul><li><strong>C(Consistency)</strong>:所有节点同一时间看到同一份数据(线性一致性)</li><li><strong>A(Availability)</strong>:每个请求都能在合理时间内拿到非错误响应</li><li><strong>P(Partition tolerance)</strong>:网络分区时,系统仍能继续工作</li></ul><p>教科书说&quot;三选二&quot;,真相是:</p><blockquote><p><strong>P 不是选项,是事实</strong>。只要你跑在网络上,分区就一定会发生(机房交换机抖一下、跨地域光纤被挖掉、防火墙规则配错)。<strong>所以选择只在 C 和 A 之间——分区时,你是宁可不可用(等数据一致),还是宁可不一致(继续服务)?</strong></p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                 网络正常时</span></span>
<span class="line"><span>            ┌───────────────────┐</span></span>
<span class="line"><span>            │  C 和 A 都能保证   │</span></span>
<span class="line"><span>            └───────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>                 网络分区时</span></span>
<span class="line"><span>        ┌──────────────────────────┐</span></span>
<span class="line"><span>        │ 必须在 C 和 A 中二选一    │</span></span>
<span class="line"><span>        │                          │</span></span>
<span class="line"><span>        │ 选 C(放弃 A):           │</span></span>
<span class="line"><span>        │   分区时拒绝请求          │</span></span>
<span class="line"><span>        │   例: ZooKeeper / etcd  │</span></span>
<span class="line"><span>        │                          │</span></span>
<span class="line"><span>        │ 选 A(放弃 C):           │</span></span>
<span class="line"><span>        │   分区时允许不一致        │</span></span>
<span class="line"><span>        │   例: Cassandra / Dynamo│</span></span>
<span class="line"><span>        └──────────────────────────┘</span></span></code></pre></div><h3 id="_1-1-「ca-系统」是个伪概念" tabindex="-1">1.1 「CA 系统」是个伪概念 <a class="header-anchor" href="#_1-1-「ca-系统」是个伪概念" aria-label="Permalink to &quot;1.1 「CA 系统」是个伪概念&quot;">​</a></h3><p>很多人说「MySQL 是 CA」——<strong>胡说</strong>。MySQL 不能容忍分区,<strong>主从分区时要么主库失联(不可用),要么强行让从库提供过期数据(不一致)</strong>,根本逃不开 CAP。</p><blockquote><p>真实情况是:<strong>没有真正的 CA 系统</strong>(除非系统只跑在一台机器上,而那就不是分布式系统)。所有分布式系统都在 CP 和 AP 之间选。</p></blockquote><h3 id="_1-2-cap-不是-系统级-选择-是-操作级-选择" tabindex="-1">1.2 CAP 不是&quot;系统级&quot;选择,是&quot;操作级&quot;选择 <a class="header-anchor" href="#_1-2-cap-不是-系统级-选择-是-操作级-选择" aria-label="Permalink to &quot;1.2 CAP 不是&quot;系统级&quot;选择,是&quot;操作级&quot;选择&quot;">​</a></h3><p>更精细的理解是:<strong>同一个系统,不同操作可以选不同侧</strong>。</p><table tabindex="0"><thead><tr><th>操作</th><th>选</th><th>理由</th></tr></thead><tbody><tr><td>转账 / 扣库存</td><td>C(强一致)</td><td>不能多扣</td></tr><tr><td>浏览商品列表</td><td>A(可用性)</td><td>看到旧数据没事,系统挂了流失大</td></tr><tr><td>点赞数 / 关注数</td><td>A(可用性)</td><td>几秒不一致用户感知不到</td></tr><tr><td>用户登录验证</td><td>C</td><td>黑名单同步要快</td></tr></tbody></table><blockquote><p><strong>不要把 CAP 当成&quot;我们公司是 CP 还是 AP 公司&quot;的标签</strong>,这是初学者最大的误解。<strong>真实的工程是:每一个操作单独选</strong>。</p></blockquote><hr><h2 id="二、base-cap-的工程化版本" tabindex="-1">二、BASE:CAP 的工程化版本 <a class="header-anchor" href="#二、base-cap-的工程化版本" aria-label="Permalink to &quot;二、BASE:CAP 的工程化版本&quot;">​</a></h2><p>BASE 是 eBay 工程师对 CAP 的实战诠释,几乎所有互联网公司都在用:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>B - Basically Available  基本可用</span></span>
<span class="line"><span>A - Soft state           软状态</span></span>
<span class="line"><span>E - Eventual consistency 最终一致</span></span></code></pre></div><h3 id="_2-1-basically-available-基本可用" tabindex="-1">2.1 Basically Available(基本可用) <a class="header-anchor" href="#_2-1-basically-available-基本可用" aria-label="Permalink to &quot;2.1 Basically Available(基本可用)&quot;">​</a></h3><p><strong>全挂 vs 全活之间还有「降级可用」</strong>:</p><ul><li>双 11 时关闭评价、推荐功能,只保留下单</li><li>抢购高峰只读缓存,不写 DB,DB 异步刷</li><li>失败时返回兜底数据(默认头像、推荐列表的备用版本)</li></ul><blockquote><p>&quot;全有或全无&quot; 是错误的可用性思维,<strong>真实系统永远在做&quot;哪些功能可以临时降级&quot;的取舍</strong>。</p></blockquote><h3 id="_2-2-soft-state-软状态" tabindex="-1">2.2 Soft State(软状态) <a class="header-anchor" href="#_2-2-soft-state-软状态" aria-label="Permalink to &quot;2.2 Soft State(软状态)&quot;">​</a></h3><p>允许系统中间状态短暂不一致:</p><ul><li>订单创建后状态从 &quot;pending&quot; → &quot;paid&quot; → &quot;shipped&quot; 可能跨服务、有延迟</li><li>不要求每一刻所有服务对状态完全一致</li></ul><h3 id="_2-3-eventual-consistency-最终一致" tabindex="-1">2.3 Eventual Consistency(最终一致) <a class="header-anchor" href="#_2-3-eventual-consistency-最终一致" aria-label="Permalink to &quot;2.3 Eventual Consistency(最终一致)&quot;">​</a></h3><p><strong>给数据一段时间,最终会一致</strong>——不是立刻,但会到。</p><ul><li>主从复制延迟 100ms ~ 几秒,最终会同步</li><li>缓存过期 / 刷新机制保证缓存最终对齐 DB</li><li>MQ 异步同步数据,可能秒级延迟,最终对齐</li></ul><blockquote><p><strong>互联网架构的胜利就是 BASE 的胜利</strong>。强一致(ACID)是金融业的根基,但电商、社交、内容都用 BASE 撑住了 100 倍以上的流量。<strong>学会 BASE 思维 = 学会互联网架构</strong>。</p></blockquote><hr><h2 id="三、一致性的「光谱」" tabindex="-1">三、一致性的「光谱」 <a class="header-anchor" href="#三、一致性的「光谱」" aria-label="Permalink to &quot;三、一致性的「光谱」&quot;">​</a></h2><p>不是只有「强一致」和「最终一致」两档,中间还有几档:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>强 ─────────────────────────────────────────────────────── 弱</span></span>
<span class="line"><span>线性 → 顺序 → 因果 → 读自己写 → 单调读 → 最终</span></span>
<span class="line"><span> |      |      |        |          |        |</span></span>
<span class="line"><span> 强     ←── 实用范围 ──→            弱</span></span></code></pre></div><h3 id="_3-1-线性一致性-linearizability" tabindex="-1">3.1 线性一致性(Linearizability) <a class="header-anchor" href="#_3-1-线性一致性-linearizability" aria-label="Permalink to &quot;3.1 线性一致性(Linearizability)&quot;">​</a></h3><p>最强,所有读都能看到最新写,<strong>像在单机上一样</strong>。 <strong>实现</strong>:Raft / Paxos / 两阶段提交,代价是高延迟。 <strong>用在</strong>:转账、扣库存、分布式锁。</p><h3 id="_3-2-顺序一致性-sequential-consistency" tabindex="-1">3.2 顺序一致性(Sequential Consistency) <a class="header-anchor" href="#_3-2-顺序一致性-sequential-consistency" aria-label="Permalink to &quot;3.2 顺序一致性(Sequential Consistency)&quot;">​</a></h3><p>所有节点看到的操作顺序一致,但不一定是实时顺序。 <strong>用在</strong>:消息队列内顺序消费。</p><h3 id="_3-3-因果一致性-causal-consistency" tabindex="-1">3.3 因果一致性(Causal Consistency) <a class="header-anchor" href="#_3-3-因果一致性-causal-consistency" aria-label="Permalink to &quot;3.3 因果一致性(Causal Consistency)&quot;">​</a></h3><p>有「因果」关系的操作必须按顺序看到(A 写了再 B 读),无关的可以乱序。 <strong>用在</strong>:朋友圈评论(评论必须在发帖之后被看到,但不同人的评论顺序不重要)。</p><h3 id="_3-4-读自己写-read-your-writes" tabindex="-1">3.4 读自己写(Read-Your-Writes) <a class="header-anchor" href="#_3-4-读自己写-read-your-writes" aria-label="Permalink to &quot;3.4 读自己写(Read-Your-Writes)&quot;">​</a></h3><p>你刚写的,你自己立刻能读到(别人不一定)。 <strong>用在</strong>:用户改完头像立刻刷新自己页面要看到新头像。</p><h3 id="_3-5-单调读-monotonic-read" tabindex="-1">3.5 单调读(Monotonic Read) <a class="header-anchor" href="#_3-5-单调读-monotonic-read" aria-label="Permalink to &quot;3.5 单调读(Monotonic Read)&quot;">​</a></h3><p>一旦看到了某版本数据,后面不会读到更老的版本。 <strong>用在</strong>:刷朋友圈不能&quot;刷新一下反而少了几条&quot;。</p><h3 id="_3-6-最终一致-eventual-consistency" tabindex="-1">3.6 最终一致(Eventual Consistency) <a class="header-anchor" href="#_3-6-最终一致-eventual-consistency" aria-label="Permalink to &quot;3.6 最终一致(Eventual Consistency)&quot;">​</a></h3><p>足够长时间后所有副本会一致,中间任意状态都可能。 <strong>用在</strong>:点赞数、关注数、推荐列表。</p><blockquote><p><strong>真实的工程是给每个数据点一个&quot;一致性档位&quot;</strong>——余额线性一致,头像读自己写,点赞数最终一致。<strong>全用最强档 = 系统跑不动;全用最弱档 = 用户骂街</strong>。</p></blockquote><hr><h2 id="四、从-cap-角度看常见组件" tabindex="-1">四、从 CAP 角度看常见组件 <a class="header-anchor" href="#四、从-cap-角度看常见组件" aria-label="Permalink to &quot;四、从 CAP 角度看常见组件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>倾向</th><th>说明</th></tr></thead><tbody><tr><td>ZooKeeper / etcd</td><td>CP</td><td>写入要多数派确认,分区时少数派不可用</td></tr><tr><td>MySQL 主从</td><td>默认 AP(异步复制)</td><td>主挂可能丢数据</td></tr><tr><td>MySQL 半同步</td><td>偏 CP</td><td>主等至少一个从确认才返回</td></tr><tr><td>Cassandra</td><td>AP(默认)</td><td>Quorum 可调到 CP</td></tr><tr><td>Redis 主从</td><td>AP</td><td>主挂自动选举,数据可能丢</td></tr><tr><td>Redis Cluster + WAIT</td><td>偏 CP</td><td>用 WAIT 命令等复制</td></tr><tr><td>Kafka</td><td>CP(配 acks=all + min.insync)</td><td>分区时少数派 broker 拒写</td></tr><tr><td>MongoDB(默认)</td><td>CP</td><td>多数派写确认</td></tr><tr><td>DynamoDB</td><td>AP</td><td>最终一致,可选强一致读</td></tr><tr><td>Spanner / TiDB</td><td>CP(强一致)</td><td>用 TrueTime / Raft + Percolator</td></tr></tbody></table><blockquote><p>选组件之前,<strong>先问自己业务在 CAP 上选哪边</strong>。<strong>用 Cassandra 存余额、用 ZooKeeper 存配置 → 都是大错</strong>。</p></blockquote><hr><h2 id="五、常见的-cap-误区" tabindex="-1">五、常见的 CAP 误区 <a class="header-anchor" href="#五、常见的-cap-误区" aria-label="Permalink to &quot;五、常见的 CAP 误区&quot;">​</a></h2><h3 id="_5-1-「我们用-nosql-所以是-ap」" tabindex="-1">5.1 「我们用 NoSQL 所以是 AP」 <a class="header-anchor" href="#_5-1-「我们用-nosql-所以是-ap」" aria-label="Permalink to &quot;5.1 「我们用 NoSQL 所以是 AP」&quot;">​</a></h3><p>不一定。MongoDB / HBase 默认偏 CP,Cassandra 默认 AP 但可调 CP。<strong>SQL / NoSQL 标签和 CAP 没有必然联系</strong>。</p><h3 id="_5-2-「最终一致-不一致」" tabindex="-1">5.2 「最终一致 = 不一致」 <a class="header-anchor" href="#_5-2-「最终一致-不一致」" aria-label="Permalink to &quot;5.2 「最终一致 = 不一致」&quot;">​</a></h3><p>错。最终一致是有<strong>收敛时间窗口</strong>的,通常是 100ms ~ 几秒。99% 的用户感知不到。</p><h3 id="_5-3-「强一致-慢」" tabindex="-1">5.3 「强一致 = 慢」 <a class="header-anchor" href="#_5-3-「强一致-慢」" aria-label="Permalink to &quot;5.3 「强一致 = 慢」&quot;">​</a></h3><p>强一致一定有额外开销(共识、同步复制),但<strong>不一定不能用</strong>。Spanner、TiDB 在跨地域强一致的同时维持 10ms 级延迟,<strong>用对算法和硬件就行</strong>。</p><h3 id="_5-4-「分区很少发生」" tabindex="-1">5.4 「分区很少发生」 <a class="header-anchor" href="#_5-4-「分区很少发生」" aria-label="Permalink to &quot;5.4 「分区很少发生」&quot;">​</a></h3><p>错。<strong>生产环境每个月都会有分区事件</strong>——交换机故障、配置错误、防火墙、跨机房抖动。<strong>没设计分区容错的系统迟早出大事</strong>。</p><h3 id="_5-5-「我们选-cp-因为我们是金融」" tabindex="-1">5.5 「我们选 CP 因为我们是金融」 <a class="header-anchor" href="#_5-5-「我们选-cp-因为我们是金融」" aria-label="Permalink to &quot;5.5 「我们选 CP 因为我们是金融」&quot;">​</a></h3><p>不绝对。金融的核心账户是 CP,但<strong>周边业务(交易记录展示、营销活动、推荐)都可以 AP</strong>。<strong>别一刀切</strong>。</p><hr><h2 id="六、pacelc-cap-的升级版" tabindex="-1">六、PACELC:CAP 的升级版 <a class="header-anchor" href="#六、pacelc-cap-的升级版" aria-label="Permalink to &quot;六、PACELC:CAP 的升级版&quot;">​</a></h2><p>更细致的模型,Daniel Abadi 提出:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PA / CELC</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果发生分区(P),选 A 或 C</span></span>
<span class="line"><span>否则(Else,正常情况)选低延迟(L)或一致性(C)</span></span></code></pre></div><p>例:</p><ul><li>DynamoDB:<strong>PA / EL</strong>——分区时选可用,正常时选低延迟</li><li>BigTable:<strong>PC / EC</strong>——任何时候都选一致</li><li>MySQL 异步复制:<strong>PA / EL</strong>——主挂时数据可能丢,正常时低延迟</li></ul><blockquote><p>PACELC 比 CAP 实用,因为它<strong>揭示了正常情况下也存在的取舍</strong>——一致性不是免费的,即使没分区,强一致也比弱一致慢。</p></blockquote><hr><h2 id="七、工程实战-四种典型一致性场景的方案" tabindex="-1">七、工程实战:四种典型一致性场景的方案 <a class="header-anchor" href="#七、工程实战-四种典型一致性场景的方案" aria-label="Permalink to &quot;七、工程实战:四种典型一致性场景的方案&quot;">​</a></h2><h3 id="_7-1-强一致需求-分布式事务" tabindex="-1">7.1 强一致需求:分布式事务 <a class="header-anchor" href="#_7-1-强一致需求-分布式事务" aria-label="Permalink to &quot;7.1 强一致需求:分布式事务&quot;">​</a></h3><p>银行转账,A 扣 100 + B 加 100 必须同时成功或同时失败。</p><p><strong>方案</strong>:</p><ul><li>单库:数据库本地事务</li><li>跨库:<strong>Saga / TCC / 2PC</strong>(详见 23 篇订单与支付)</li><li>跨服务:消息事务表 + 对账兜底</li></ul><h3 id="_7-2-读自己写-session-粘滞或主库读" tabindex="-1">7.2 读自己写:Session 粘滞或主库读 <a class="header-anchor" href="#_7-2-读自己写-session-粘滞或主库读" aria-label="Permalink to &quot;7.2 读自己写:Session 粘滞或主库读&quot;">​</a></h3><p>用户改了头像立刻刷新页面要看到。</p><p><strong>方案</strong>:</p><ul><li>用户的写后 N 秒内,读请求强制走主库</li><li>或者在前端缓存「我刚改的版本」,展示用 max(server, local)</li></ul><h3 id="_7-3-单调读-session-粘滞-版本号" tabindex="-1">7.3 单调读:Session 粘滞 + 版本号 <a class="header-anchor" href="#_7-3-单调读-session-粘滞-版本号" aria-label="Permalink to &quot;7.3 单调读:Session 粘滞 + 版本号&quot;">​</a></h3><p>刷新朋友圈不能丢条。</p><p><strong>方案</strong>:</p><ul><li>同一用户的读请求路由到同一个从库副本</li><li>或者带版本号 / 游标,服务端保证返回数据 ≥ 客户端已有版本</li></ul><h3 id="_7-4-最终一致-异步复制-对账" tabindex="-1">7.4 最终一致:异步复制 + 对账 <a class="header-anchor" href="#_7-4-最终一致-异步复制-对账" aria-label="Permalink to &quot;7.4 最终一致:异步复制 + 对账&quot;">​</a></h3><p>点赞数、统计、推荐。</p><p><strong>方案</strong>:</p><ul><li>写主 → 异步同步到 Redis / 副本 / ES</li><li>定时对账修复偏差</li></ul><hr><h2 id="八、cap-与组织决策" tabindex="-1">八、CAP 与组织决策 <a class="header-anchor" href="#八、cap-与组织决策" aria-label="Permalink to &quot;八、CAP 与组织决策&quot;">​</a></h2><p>CAP 不只是技术决策,<strong>也是产品 + 业务决策</strong>。让产品参与:</p><table tabindex="0"><thead><tr><th>数据类型</th><th>问产品的问题</th><th>通常答案</th></tr></thead><tbody><tr><td>余额</td><td>能不能错账?</td><td>不能 → CP</td></tr><tr><td>库存</td><td>能不能超卖?</td><td>不能 → CP(或预占 + 异步对账)</td></tr><tr><td>头像</td><td>改了几秒后才生效行吗?</td><td>行 → AP / 最终</td></tr><tr><td>订单状态</td><td>用户必须立刻看到?</td><td>自己的订单要(读自己写),别人的订单可以延迟</td></tr><tr><td>评论</td><td>几秒后才显示行吗?</td><td>行 → AP</td></tr></tbody></table><blockquote><p><strong>跟产品聊清楚每类数据的&quot;可容忍延迟&quot;和&quot;可容忍错误率&quot;,CAP 选择就自然出来</strong>。<strong>纯技术拍板的 CAP 决策几乎都是错的</strong>——因为技术不知道业务真正在乎什么。</p></blockquote><hr><h2 id="九、踩坑提醒" tabindex="-1">九、踩坑提醒 <a class="header-anchor" href="#九、踩坑提醒" aria-label="Permalink to &quot;九、踩坑提醒&quot;">​</a></h2><ol><li><strong>背&quot;三选二&quot;——错</strong> ,应该是&quot;分区时二选一&quot;</li><li><strong>以为 P 可选</strong>——P 不是选项,是物理事实</li><li><strong>整系统打 CP / AP 标签</strong>——应该按操作 / 按数据细分</li><li><strong>以为 NoSQL = AP</strong>——MongoDB / HBase 默认 CP</li><li><strong>强一致全用 2PC</strong>——2PC 性能差,90% 场景 Saga / TCC 更好</li><li><strong>最终一致不算&quot;对账机制&quot;</strong>——异步复制可能丢消息,必须有对账兜底</li><li><strong>用 Redis 当强一致存储</strong>——Redis 主从异步,主挂丢数据,<strong>别用它存余额</strong></li><li><strong>忽略读自己写需求</strong>——用户最容易感知&quot;改了没生效&quot;,这一类必须特殊处理</li><li><strong>不告诉产品 CAP 含义</strong>——产品不知道你&quot;为了性能放弃了一致性&quot;,出事甩你锅</li><li><strong>盲目追求线性一致性</strong>——99% 的业务用因果一致 / 最终一致就够了,<strong>强一致是奢侈品</strong></li></ol><hr><p>下一篇:<code>05-高可用三件套.md</code>,讲让系统&quot;永不挂&quot;的三个基础动作:<strong>冗余(多副本)、故障转移(自动切换)、健康检查(知道谁活着)</strong>——以及为什么&quot;99.99% 可用性&quot;听起来低,实际上意味着一年只能挂 52 分钟,这意味着什么样的工程努力。</p>`,100)])])}const g=a(e,[["render",r]]);export{u as __pageData,g as default};
